<?php
 namespace FilesManager\Traits; trait Loggable { protected function log(string $message, string $level = 'info'): void { if ($level === 'debug' && !$this->isDebugEnabled()) { return; } $prefix = '[FilesManager]'; $formatted = $prefix . ' ' . strtoupper($level) . ': ' . $message; error_log($formatted); } protected function logError(string $message, array $context = []): void { $contextSuffix = ''; if (!empty($context)) { $contextSuffix = ' ' . json_encode($context, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES); } $this->log($message . $contextSuffix, 'error'); } protected function isDebugEnabled(): bool { if (property_exists($this, 'debug')) { return (bool) $this->debug; } return false; } } 